const input = $json.body ?? $json;
const clinicId = input.clinicId || input.clinic_id;
const action = String(input.action || 'status').toLowerCase();
const reset = action === 'refresh' || Boolean(input.reset);
const instanceInput = input.instanceName || input.instance;

const sbBase = ($env.SUPABASE_URL || 'http://host.docker.internal:54321').replace(/\/$/, '');
const sbKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const evoBase = ($env.EVOLUTION_API_URL || 'http://evolution-api:8080').replace(/\/$/, '');
const evoKey = $env.EVOLUTION_API_KEY;
const whBase = ($env.WEBHOOK_URL || $env.N8N_WEBHOOK_URL || 'https://api.nefalixai.com/').replace(/\/$/, '');
const inboxWebhook = `${whBase}/webhook/nefalix/inbox/incoming`;

if (!clinicId) throw new Error('clinicId gerekli');
if (!sbKey) throw new Error('SUPABASE_SERVICE_ROLE_KEY eksik (VPS .env)');
if (!evoKey) throw new Error('EVOLUTION_API_KEY eksik (VPS .env)');

const sbH = {
  apikey: sbKey,
  Authorization: `Bearer ${sbKey}`,
  'Content-Type': 'application/json',
  Prefer: 'return=representation',
};

async function sbGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET',
    url: `${sbBase}/rest/v1/${path}`,
    headers: sbH,
    json: true,
  });
}

async function sbPatch(path, body) {
  return await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${sbBase}/rest/v1/${path}`,
    headers: sbH,
    body,
    json: true,
  });
}

const clinics = await sbGet.call(this, `clinics?select=id,name,sector,evolution_instance_name,integration_config,slug&id=eq.${clinicId}&limit=1`);
const clinic = Array.isArray(clinics) ? clinics[0] : null;
if (!clinic) throw new Error('Firma bulunamadı');
if ((clinic.sector || 'clinic') !== 'clinic') {
  throw new Error('WhatsApp QR şu an yalnızca klinik sektöründe');
}

function normInstance(raw) {
  const s = String(raw || '')
    .toLowerCase()
    .replace(/[^a-z0-9-]+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 50);
  if (!/^[a-z0-9][a-z0-9-]{1,48}[a-z0-9]$/.test(s)) {
    throw new Error('Geçersiz instance adı (ör. medident-pilot)');
  }
  return s;
}

const instance = normInstance(instanceInput || clinic.evolution_instance_name || clinic.slug);

if (instanceInput && instance !== clinic.evolution_instance_name) {
  await sbPatch.call(this, `clinics?id=eq.${clinicId}`, { evolution_instance_name: instance });
}

async function evo(method, path, body) {
  return await this.helpers.httpRequest({
    method,
    url: `${evoBase}${path}`,
    headers: { apikey: evoKey, 'Content-Type': 'application/json', Accept: 'application/json' },
    body,
    json: true,
  });
}

async function connectionState(inst) {
  const data = await evo.call(this, 'GET', `/instance/connectionState/${encodeURIComponent(inst)}`);
  const state = data?.instance?.state || data?.state || 'unknown';
  return String(state).toLowerCase();
}

async function fetchQr(inst) {
  const data = await evo.call(this, 'GET', `/instance/connect/${encodeURIComponent(inst)}`);
  const b64 = data?.base64 || data?.qrcode?.base64 || '';
  if (!b64 || b64 === 'null') throw new Error('QR alınamadı — Yenile\'ye basın');
  return b64.startsWith('data:') ? b64 : `data:image/png;base64,${b64}`;
}

async function ensureInstance(inst) {
  try {
    await connectionState.call(this, inst);
  } catch {
    await evo.call(this, 'POST', '/instance/create', {
      instanceName: inst,
      integration: 'WHATSAPP-BAILEYS',
      qrcode: true,
    });
  }
}

async function resetInstance(inst) {
  await evo.call(this, 'DELETE', `/instance/logout/${encodeURIComponent(inst)}`).catch(() => {});
  await evo.call(this, 'DELETE', `/instance/delete/${encodeURIComponent(inst)}`).catch(() => {});
  await ensureInstance.call(this, inst);
}

async function configureWebhook(inst) {
  await evo.call(this, 'POST', `/webhook/set/${encodeURIComponent(inst)}`, {
    webhook: {
      enabled: true,
      url: inboxWebhook,
      webhookByEvents: false,
      webhookBase64: false,
      events: ['MESSAGES_UPSERT'],
    },
  });
}

async function markConnected() {
  const cfg = { ...(clinic.integration_config || {}), evolution_connected: true };
  await sbPatch.call(this, `clinics?id=eq.${clinicId}`, { integration_config: cfg });
}

if (action === 'start' || action === 'refresh') {
  if (reset) await resetInstance.call(this, instance);
  else await ensureInstance.call(this, instance);
  const state = await connectionState.call(this, instance);
  if (state === 'open') {
    await configureWebhook.call(this, instance);
    await markConnected.call(this);
    return [{
      json: {
        ok: true,
        instance,
        state: 'open',
        connected: true,
        qr: null,
        hint: 'WhatsApp bağlı — Inbox webhook ayarlandı.',
      },
    }];
  }
  const qr = await fetchQr.call(this, instance);
  return [{
    json: {
      ok: true,
      instance,
      state,
      connected: false,
      qr,
      hint: 'Telefonda WhatsApp → Bağlı cihazlar → Cihaz bağla → QR okutun (60 sn).',
    },
  }];
}

if (action === 'status') {
  const state = await connectionState.call(this, instance);
  if (state === 'open') {
    await configureWebhook.call(this, instance);
    await markConnected.call(this);
    return [{ json: { ok: true, instance, state: 'open', connected: true, qr: null } }];
  }
  let qr = null;
  try {
    qr = await fetchQr.call(this, instance);
  } catch {
    /* QR süresi dolmuş olabilir */
  }
  return [{ json: { ok: true, instance, state, connected: false, qr } }];
}

throw new Error('Geçersiz action (start | refresh | status)');
